import tarfile


def extract(source):
    """
    Extracts a tar file and stores it in the destination folder. 
    If the destination already exists then the destination is deleted first before being recreated.
    The tar file is extracted to the current working directory.
    :param source: Path of the tar file provided by user.
    """
    source = os.path.normpath(source)

    # Get the path and filename of the tarfile without extension using splitext() method
    path, filename = os.path.split(source)
    
    # Get the file name without extension from the source parameter using split() 
    filename = os.path.splitext(filename)[0] 

    # Get the destination folder name based on the date
    today = str(date.today())
    dest_foldername = 'Extracted_Files_' + today

    # If the destination folder already exists then delete it first before recreating it
    if os.path.exists(dest_foldername):
        shutil.rmtree(dest_foldername)

    # Create a new directory in the current working dir using mkdir() method
    os.mkdir(dest_foldername)

    # Get a handle to the tar file and extract it to the destination folder
    with tarfile.open(source, 'r') as tar:
        tar.extractall(path=dest_foldername)